def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    # Clean object values (remove quotes from dates, etc.)
    def clean_object(obj):
        if obj.startswith('"') and obj.endswith('"'):
            return obj[1:-1]
        return obj

    # Group triples by subject for complex sentence building
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Mapping predicates to phrase generators with better grammar
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"founded by {o}"
    def key_person(s, o): return f"{o} is a key person"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"distributed by {o}"
    def birth_place(s, o): return f"born in {o}"
    def nationality(s, o):
        # Handle nationality more naturally - convert to adjective form
        if o == "Americans":
            return "American"
        elif o == "United States":
            return "American"
        elif o.endswith("s"):
            nationality_adj = o[:-1]
        else:
            nationality_adj = o
        return nationality_adj
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Build complex sentence from all triples
    sentence_parts = []

    for subject, subject_trips in subject_triples.items():
        # Sort triples by priority (more important info first)
        priority = ["creator", "fullName", "alternativeName", "nationality", "birthPlace", "award", "child"]
        sorted_trips = sorted(subject_trips, key=lambda t: priority.index(t.predicate) if t.predicate in priority else len(priority))

        # Build subject phrase with proper spacing
        if len(sorted_trips) == 1:
            t = sorted_trips[0]
            func = phrase_funcs.get(t.predicate)
            if func:
                if t.predicate == "nationality":
                    sentence_parts.append(f"{subject} is {func(subject, t.object)}.")
                else:
                    sentence_parts.append(f"{subject}, {func(subject, t.object)}.")
            else:
                sentence_parts.append(f"{subject} {t.predicate} {t.object}.")
        else:
            # Multiple triples for same subject - build complex sentence
            main_clause = f"{subject}"
            clauses = []

            for i, t in enumerate(sorted_trips):
                func = phrase_funcs.get(t.predicate)
                if func:
                    if i == 0:
                        # First predicate becomes main verb
                        if t.predicate == "nationality":
                            clauses.append(f"is {func(subject, t.object)}")
                        else:
                            clauses.append(f", {func(subject, t.object)}")
                    else:
                        # Subsequent predicates become relative clauses
                        if t.predicate == "fullName":
                            clauses.append(f", {func(subject, t.object)}")
                        elif t.predicate == "alternativeName":
                            clauses.append(f", {func(subject, t.object)}")
                        else:
                            clauses.append(f", {func(subject, t.object)}")

            sentence_parts.append(main_clause + "".join(clauses) + ".")

    # Combine all subject sentences into one complex sentence
    if len(sentence_parts) == 1:
        return sentence_parts[0]
    else:
        # Connect subjects with relative clauses for complex sentence
        result = sentence_parts[0]
        for part in sentence_parts[1:]:
            if not part.startswith(sentence_parts[0].split()[0] if sentence_parts[0].split() else ""):
                result += f", and {part}"
        return result

